import { styled } from 'styled-components'

const StyledMenuList = styled.main`
  padding-top: 80px;
  padding-bottom: 120px;

  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  gap: 32px;

  width: min-content;
  margin: auto;
`
export default StyledMenuList
